  if (module.id === 'privacy_policy') return <PrivacyPolicy />;
  if (module.id === 'terms_of_service') return <TermsOfService />;

  return (
    <div className="max-w-7xl mx-auto space-y-16 pb-24 px-4 animate-in fade-in duration-700">
